+type reloadTransaction struct {
+	mu       sync.RWMutex
+	path     string
+	logger   *slog.Logger
+	status   api_v1.ReloadStatus
+	lastGood *config.Config
+}
+
+func defaultReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}, ErrorCategory: "none"}
+}
+
+func newReloadTransaction(path string, logger *slog.Logger) *reloadTransaction {
+	t := &reloadTransaction{path: path, logger: logger, status: defaultReloadStatus()}
+	b, err := os.ReadFile(path)
+	if err == nil && json.Unmarshal(b, &t.status) == nil {
+		if t.status.AppliedReloaders == nil { t.status.AppliedReloaders = []string{} }
+		if t.status.ReloaderTimingsMS == nil { t.status.ReloaderTimingsMS = map[string]float64{} }
+	} else if err != nil && !os.IsNotExist(err) {
+		logger.Warn("Unable to read persisted reload status", "err", err)
+	} else if err == nil {
+		logger.Warn("Unable to parse persisted reload status")
+	}
+	return t
+}
+
+func (t *reloadTransaction) Status() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	s := t.status
+	s.AppliedReloaders = append([]string{}, s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]float64, len(t.status.ReloaderTimingsMS))
+	for k, v := range t.status.ReloaderTimingsMS { s.ReloaderTimingsMS[k] = v }
+	return s
+}
+
+func (t *reloadTransaction) record(s api_v1.ReloadStatus) {
+	t.mu.Lock()
+	t.status = s
+	b, err := json.Marshal(s)
+	if err == nil {
+		if err = os.MkdirAll(filepath.Dir(t.path), 0o755); err == nil {
+			err = os.WriteFile(t.path, b, 0o644)
+		}
+	}
+	t.mu.Unlock()
+	if err != nil { t.logger.Warn("Unable to persist reload status", "err", err) }
+}
