+	if err != nil {
+		if !initial { tx.record(api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339Nano), ErrorCategory: "load_error", ErrorMessage: err.Error(), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}}) }
+		configSuccess.Set(0); callback(false)
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil { conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig }
+
+	s := defaultReloadStatus()
+	if !initial { s.LastReloadID = time.Now().UTC().Format(time.RFC3339Nano) }
+	for _, rl := range rls {
+		start := time.Now()
+		err = rl.reloader(conf)
+		s.ReloaderTimingsMS[rl.name] = float64(time.Since(start).Microseconds()) / 1000
+		if err != nil {
+			s.LastReloadSuccessful = false; s.ErrorCategory = "apply_error"; s.ErrorMessage = err.Error(); s.FailedReloader = rl.name
