+				}
+			}
+			if !initial { tx.record(s) }; configSuccess.Set(0); callback(false)
+			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+		}
+		s.AppliedReloaders = append(s.AppliedReloaders, rl.name)
+	}
+	updateGoGC(conf, logger); interval.Set(conf.GlobalConfig.EvaluationInterval)
+	tx.lastGood = conf
+	configSuccess.Set(1); configSuccessTime.SetToCurrentTime(); callback(true)
+	if !initial { s.LastReloadSuccessful = true; s.ErrorCategory = "none"; tx.record(s) }
